        JSONParser parser = new JSONParser();
        JSONArray teams = (JSONArray) parser.parse(new FileReader(filePath));
        TreeNode root = new TreeNode("Organization", 0);

        for (Object teamObj : teams) {
            JSONObject team = (JSONObject) teamObj;
            String teamName = (String) team.get("teamName");
            JSONArray members = (JSONArray) team.get("members");
            int memberCount = members.size();

            TreeNode teamNode = new TreeNode(teamName, memberCount);
            addToTree(root, teamNode, 1);
