    public static class Node {
        int id;
        String cityName;
        List<Edge> edges;

        public Node(int id, String cityName) {
            this.id = id;
            this.cityName = cityName;
            this.edges = new ArrayList<>();
        }
    }

    public static class Edge {
        Node destination;
        int weight;

        public Edge(Node destination, int weight) {
            this.destination = destination;
            this.weight = weight;
        }
    }

    public static List<Node> buildGraphFromJSON(String filePath) throws IOException, ParseException {
        JSONParser parser = new JSONParser();
        JSONArray citiesArray = (JSONArray) parser.parse(new FileReader(filePath));
        List<Node> nodes = new ArrayList<>();
        Map<String, Node> cityToNode = new HashMap<>();

        // Create nodes with unique IDs (0 to 49)
        for (int i = 0; i < citiesArray.size(); i++) {
            JSONObject cityObj = (JSONObject) citiesArray.get(i);
            String cityName = (String) cityObj.get("cityName");
            Node node = new Node(i, cityName);
            nodes.add(node);
            cityToNode.put(cityName, node);
        }

        // Add edges with weights in [10, 100]
        for (int i = 0; i < citiesArray.size(); i++) {
            JSONObject cityObj = (JSONObject) citiesArray.get(i);
            JSONArray distances = (JSONArray) cityObj.get("distances");
            Node sourceNode = nodes.get(i);

            for (int j = 0; j < distances.size(); j++) {
                long distance = (long) distances.get(j);
                int weight = (int) distance;
                // Ensure weight is within [10, 100]
                weight = Math.max(10, Math.min(weight, 100));
                if (i != j) { // Avoid self-loops
                    Node destNode = nodes.get(j);
                    sourceNode.edges.add(new Edge(destNode, weight));
                }
            }
        }

        return nodes;
    }
}
