import json

def validate_tree_structure(json_file_path):
    # Read the JSON file
    with open(json_file_path, 'r') as file:
        tree_data = json.load(file)

    # Initialize a dictionary to track parent counts for each node
    parent_counts = {}
    all_nodes = set()

    # First pass: collect all nodes and initialize parent counts
    for node in tree_data:
        node_id = node['id']
        if node_id < 1 or node_id > 100:
            raise ValueError(f"Node id {node_id} is out of range (1-100).")
        all_nodes.add(node_id)
        parent_counts[node_id] = 0

        children = node.get('children', [])
        if len(children) > 3:
            raise ValueError(f"Node {node_id} has more than 3 children.")
        for child_id in children:
            if child_id < 1 or child_id > 100:
                raise ValueError(f"Child id {child_id} is out of range (1-100).")

    # Second pass: count parents for each child
    for node in tree_data:
        children = node.get('children', [])
        for child_id in children:
            parent_counts[child_id] += 1

    # Generate the report
    report = []
    for node_id in sorted(all_nodes):
        report.append({
            'id': node_id,
            'has_unique_parent': parent_counts[node_id] <= 1
        })

    return json.dumps(report, indent=2)

# Example usage:
