using namespace std;

struct Employee {
    string name;
    vector<int> salaries;
};

struct TreeNode {
    int maxSalary;
    Employee* employee;
    vector<TreeNode*> children;
    TreeNode(int val, Employee* emp) : maxSalary(val), employee(emp) {}
};

TreeNode* buildTree(const vector<Employee>& employees, const vector<pair<string, string>>& hierarchy) {
    unordered_map<string, TreeNode*> empMap;
    unordered_map<string, Employee*> empData;
    vector<TreeNode*> nodes;

    // Create Employee pointers and find max salary
    for (const auto& emp : employees) {
        int maxSal = *max_element(emp.salaries.begin(), emp.salaries.end());
        Employee* newEmp = new Employee(emp);
        TreeNode* newNode = new TreeNode(maxSal, newEmp);
        empMap[emp.name] = newNode;
        empData[emp.name] = newEmp;
        nodes.push_back(newNode);
    }

    // Build tree structure
    TreeNode* root = nullptr;
    for (const auto& rel : hierarchy) {
        string manager = rel.first;
        string employee = rel.second;

        if (empMap.find(manager) != empMap.end() && empMap.find(employee) != empMap.end()) {
            TreeNode* mgrNode = empMap[manager];
            TreeNode* empNode = empMap[employee];

            if (mgrNode->children.size() < 2) {
                mgrNode->children.push_back(empNode);
            }
        }
    }

    // Find root (node with no parent)
    for (TreeNode* node : nodes) {
        bool isRoot = true;
        for (const auto& rel : hierarchy) {
            if (rel.second == node->employee->name) {
                isRoot = false;
                break;
            }
        }
        if (isRoot) {
            root = node;
            break;
        }
    }

    return root;
}

// Helper function to enforce max depth of 3
void enforceMaxDepth(TreeNode* root, int currentDepth = 1) {
    if (!root || currentDepth > 3) return;

    for (TreeNode* child : root->children) {
        enforceMaxDepth(child, currentDepth + 1);
        if (currentDepth == 3) {
            // Remove all children at depth 3
            child->children.clear();
        }
    }
}

TreeNode* createEmployeeTree(const vector<Employee>& employees, const vector<pair<string, string>>& hierarchy) {
    TreeNode* root = buildTree(employees, hierarchy);
    enforceMaxDepth(root);
    return root;
}
