    public static List<ProductSales> processProductSales(String inputFilePath) throws Exception {
        JSONParser parser = new JSONParser();
        JSONArray products = (JSONArray) parser.parse(new FileReader(inputFilePath));
        List<ProductSales> productSalesList = new ArrayList<>();

        for (Object obj : products) {
            JSONObject product = (JSONObject) obj;
