            int totalSales = 0;

            for (Object saleObj : salesArray) {
                long sale = (long) saleObj;
                totalSales += sale;
            }

            // Ensure totalSales does not exceed 5000
            totalSales = Math.min(totalSales, 5000);
            productSalesList.add(new ProductSales(productID, totalSales));
        }

        // Sort in descending order based on totalSales
        Collections.sort(productSalesList, new Comparator<ProductSales>() {
            @Override
            public int compare(ProductSales p1, ProductSales p2) {
                return Integer.compare(p2.getTotalSales(), p1.getTotalSales());
            }
        });

        return productSalesList;
    }

    public static class ProductSales {
        private String productID;
        private int totalSales;

        public ProductSales(String productID, int totalSales) {
            this.productID = productID;
            this.totalSales = totalSales;
        }

