        String filePath = "employees.json"; // Replace with your file path
        List<Employee> employees = readEmployeesFromFile(filePath);
        List<Edge> edges = computeEdges(employees);
        printGraph(employees, edges);
    }

    private static List<Employee> readEmployeesFromFile(String filePath) throws Exception {
        FileReader reader = new FileReader(filePath);
        JSONTokener tokener = new JSONTokener(reader);
        JSONArray jsonArray = new JSONArray(tokener);
        List<Employee> employees = new ArrayList<>();

        for (int i = 0; i < jsonArray.length(); i++) {
            JSONObject jsonObject = jsonArray.getJSONObject(i);
            int id = jsonObject.getInt("id");
            int salary = jsonObject.getInt("salary");
            employees.add(new Employee(id, salary));
        }

        return employees;
    }

    private static List<Edge> computeEdges(List<Employee> employees) {
        List<Edge> edges = new ArrayList<>();
        for (int i = 0; i < employees.size(); i++) {
            for (int j = i + 1; j < employees.size(); j++) {
                int diff = Math.abs(employees.get(i).salary - employees.get(j).salary);
                if (diff < 5000 && edges.size() < 50) {
                    edges.add(new Edge(employees.get(i).id, employees.get(j).id, diff));
                }
            }
        }
        return edges;
    }

