std::tuple<int, int, int> computeEmployeeHours(const std::string& filePath) {
    std::ifstream file(filePath);
    std::string line;
    std::map<int, int> employeeHours;

    // Skip header line
    std::getline(file, line);

    while (std::getline(file, line)) {
        std::stringstream ss(line);
        std::string token;
        int employeeID, hoursWorked;

        // Read EmployeeID
        std::getline(ss, token, ',');
        employeeID = std::stoi(token);

        // Read HoursWorked
        std::getline(ss, token, ',');
        hoursWorked = std::stoi(token);

        // Clamp hours to [0, 160]
        hoursWorked = std::max(0, std::min(160, hoursWorked));

        // Accumulate hours
        employeeHours[employeeID] += hoursWorked;
    }

    // Extract unique EmployeeIDs and sort them
    std::vector<int> employeeIDs;
    for (const auto& pair : employeeHours) {
        employeeIDs.push_back(pair.first);
    }
    std::sort(employeeIDs.begin(), employeeIDs.end());

    // Prepare tuple based on number of unique EmployeeIDs
    if (employeeIDs.size() == 1) {
        return std::make_tuple(employeeHours[employeeIDs[0]], 0, 0);
    } else if (employeeIDs.size() == 2) {
