        userid = entry['userid']
        user_stats[userid]['session_time_sum'] += entry['session_time']
        user_stats[userid]['session_count'] += 1
        user_stats[userid]['actions_count'] += len(entry['actions'])

    result = {}
    for userid, stats in user_stats.items():
        avg_session_time = round(stats['session_time_sum'] / stats['session_count'])
        result[userid] = {
            'average_session_time': int(avg_session_time),
            'total_actions': int(stats['actions_count'])
        }

    return json.dumps(result)
