use std::collections::HashMap;

#[derive(Debug)]
struct TreeNode {
    id: i32,
    children: Vec<TreeNode>,
}

fn build_tree(nodes: &[(i32, i32)]) -> Option<TreeNode> {
    let mut node_map: HashMap<i32, Vec<i32>> = HashMap::new();
    let mut id_to_node: HashMap<i32, TreeNode> = HashMap::new();

    // Group children by parent ID
    for &(id, parent_id) in nodes {
        node_map.entry(parent_id).or_default().push(id);
    }

    // Build nodes starting from the root (ID 0)
    build_subtree(0, &node_map, &mut id_to_node, 1)?;

    id_to_node.remove(&0)
}

fn build_subtree(
    id: i32,
    node_map: &HashMap<i32, Vec<i32>>,
    id_to_node: &mut HashMap<i32, TreeNode>,
    depth: usize,
) -> Option<()> {
    if depth > 3 {
        return None;
    }

    let children_ids = node_map.get(&id).cloned().unwrap_or_default();
    if children_ids.len() > 2 {
        return None;
    }

    let mut children = Vec::new();
    for child_id in children_ids {
        build_subtree(child_id, node_map, id_to_node, depth + 1)?;
        if let Some(child_node) = id_to_node.remove(&child_id) {
            children.push(child_node);
        }
    }

    id_to_node.insert(id, TreeNode { id, children });
    Some(())
}
