use std::collections::HashSet;
use std::time::{SystemTime, UNIX_EPOCH};

fn unique_timestamps_in_last_hour(timestamps: Vec<i64>) -> HashSet<i64> {
    let current_time = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs() as i64;
    let one_hour_ago = current_time - 3600;

    let mut unique_timestamps: HashSet<i64> = timestamps
        .into_iter()
        .filter(|&ts| ts >= one_hour_ago && ts <= current_time)
        .collect();

    if unique_timestamps.len() > 10 {
        let mut sorted: Vec<i64> = unique_timestamps.into_iter().collect();
        sorted.sort();
        unique_timestamps = sorted.into_iter().take(10).collect();
    }

    unique_timestamps
}
